// 司乃耳定律：n1 sinθ1 = n2 sinθ2
var n1=1.0, n2=1.33, cx=150, cy=100, len=100;
var angle=document.getElementById("angle");
var val=document.getElementById("val");
var inc=document.getElementById("incident");
var ref=document.getElementById("refract");
function update(){
  var a1=angle.value*Math.PI/180;
  val.textContent=angle.value;
  // 入射光線（從左上到交界點）
  inc.setAttribute("x1", cx-Math.sin(a1)*len);
  inc.setAttribute("y1", cy-Math.cos(a1)*len);
  inc.setAttribute("x2", cx); inc.setAttribute("y2", cy);
  // 折射角
  var s2=n1*Math.sin(a1)/n2; var a2=Math.asin(Math.min(1,s2));
  ref.setAttribute("x1", cx); ref.setAttribute("y1", cy);
  ref.setAttribute("x2", cx+Math.sin(a2)*len);
  ref.setAttribute("y2", cy+Math.cos(a2)*len);
}
angle.addEventListener("input", update); update();

